24: /**
25:  * Wraps retry state for the router.
26:  */
27: class RetryStateImpl : public RetryState {
28: public:
29:   static std::unique_ptr<RetryStateImpl>
30:   create(const RetryPolicy& route_policy, Http::RequestHeaderMap& request_headers,
31:          const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
32:          RouteStatsContextOptRef route_stats_context,
33:          Server::Configuration::CommonFactoryContext& context, Event::Dispatcher& dispatcher,
34:          Upstream::ResourcePriority priority);
35:   ~RetryStateImpl() override;
36: 
37:   /**
38:    * Returns the RetryPolicy extracted from the x-envoy-retry-on header.
39:    * @param config is the value of the header.
40:    * @return std::pair<uint32_t, bool> the uint32_t is a bitset representing the
41:    *         valid retry policies in @param config. The bool is TRUE iff all the
42:    *         policies specified in @param config are valid.
43:    */
44:   static std::pair<uint32_t, bool> parseRetryOn(absl::string_view config);
45: 
46:   /**
47:    * Returns the RetryPolicy extracted from the x-envoy-retry-grpc-on header.
48:    * @param config is the value of the header.
49:    * @return std::pair<uint32_t, bool> the uint32_t is a bitset representing the
50:    *         valid retry policies in @param config. The bool is TRUE iff all the
51:    *         policies specified in @param config are valid.
52:    */
53:   static std::pair<uint32_t, bool> parseRetryGrpcOn(absl::string_view retry_grpc_on_header);
54: 
55:   // Router::RetryState
56:   bool enabled() override { return retry_on_ != 0; }
57:   absl::optional<std::chrono::milliseconds>
58:   parseResetInterval(const Http::ResponseHeaderMap& response_headers) const override;
59:   RetryStatus shouldRetryHeaders(const Http::ResponseHeaderMap& response_headers,
60:                                  const Http::RequestHeaderMap& original_request,
61:                                  DoRetryHeaderCallback callback) override;
62:   // Returns if the retry policy would retry the passed headers and how. Does not
63:   // take into account circuit breaking or remaining tries.
64:   RetryDecision wouldRetryFromHeaders(const Http::ResponseHeaderMap& response_headers,
65:                                       const Http::RequestHeaderMap& original_request,
66:                                       bool& disable_early_data) override;
67:   RetryStatus shouldRetryReset(Http::StreamResetReason reset_reason, Http3Used http3_used,
68:                                DoRetryResetCallback callback,
69:                                bool upstream_request_started) override;
70:   RetryStatus shouldHedgeRetryPerTryTimeout(DoRetryCallback callback) override;
71: 
72:   void onHostAttempted(Upstream::HostDescriptionConstSharedPtr host) override {
73:     std::for_each(retry_host_predicates_.begin(), retry_host_predicates_.end(),
74:                   [&host](auto predicate) { predicate->onHostAttempted(host); });
75:     if (retry_priority_) {
76:       retry_priority_->onHostAttempted(host);
77:     }
78:   }
79: 
80:   bool shouldSelectAnotherHost(const Upstream::Host& host) override {
81:     return std::any_of(
82:         retry_host_predicates_.begin(), retry_host_predicates_.end(),
83:         [&host](auto predicate) { return predicate->shouldSelectAnotherHost(host); });
84:   }
85: 
86:   const Upstream::HealthyAndDegradedLoad& priorityLoadForRetry(
87:       const Upstream::PrioritySet& priority_set,
88:       const Upstream::HealthyAndDegradedLoad& original_priority_load,
89:       const Upstream::RetryPriority::PriorityMappingFunc& priority_mapping_func) override {
90:     if (!retry_priority_) {
91:       return original_priority_load;
92:     }
93:     return retry_priority_->determinePriorityLoad(priority_set, original_priority_load,
94:                                                   priority_mapping_func);
95:   }
96: 
97:   uint32_t hostSelectionMaxAttempts() const override { return host_selection_max_attempts_; }
98: 
99:   bool isAutomaticallyConfiguredForHttp3() const { return auto_configured_for_http3_; }
100: 
101: private:
102:   RetryStateImpl(const RetryPolicy& route_policy, Http::RequestHeaderMap& request_headers,
103:                  const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
104:                  RouteStatsContextOptRef route_stats_context,
105:                  Server::Configuration::CommonFactoryContext& context,
106:                  Event::Dispatcher& dispatcher, Upstream::ResourcePriority priority,
107:                  bool auto_configured_for_http3);
108: 
109:   void enableBackoffTimer();
110:   void resetRetry();
111:   // Returns if the retry policy would retry the reset and how. Does not
112:   // take into account circuit breaking or remaining tries.
113:   // disable_http3: populated to tell the caller whether to disable http3 or not when the return
114:   // value indicates retry.
115:   RetryDecision wouldRetryFromReset(const Http::StreamResetReason reset_reason,
116:                                     Http3Used http3_used, bool& disable_http3,
117:                                     bool upstream_request_started);
118:   RetryStatus shouldRetry(RetryDecision would_retry, DoRetryCallback callback);
119: 
120:   const Upstream::ClusterInfo& cluster_;
121:   const VirtualCluster* vcluster_;
122:   RouteStatsContextOptRef route_stats_context_;
123:   Runtime::Loader& runtime_;
124:   Random::RandomGenerator& random_;
125:   Event::Dispatcher& dispatcher_;
126:   TimeSource& time_source_;
127:   DoRetryCallback backoff_callback_;
128:   Event::SchedulableCallbackPtr next_loop_callback_;
129:   Event::TimerPtr retry_timer_;
130:   BackOffStrategyPtr backoff_strategy_;
131:   BackOffStrategyPtr ratelimited_backoff_strategy_{};
132:   std::vector<Upstream::RetryHostPredicateSharedPtr> retry_host_predicates_;
133:   Upstream::RetryPrioritySharedPtr retry_priority_;
134:   std::vector<uint32_t> retriable_status_codes_;
135:   std::vector<Http::HeaderMatcherSharedPtr> retriable_headers_;
136:   std::vector<ResetHeaderParserSharedPtr> reset_headers_{};
137:   std::chrono::milliseconds reset_max_interval_{};
138: 
139:   // Keep small members (bools, enums and int32s) at the end of class, to reduce alignment overhead.
140:   uint32_t retry_on_{};
141:   uint32_t retries_remaining_{};
142:   uint32_t host_selection_max_attempts_;
143:   Upstream::ResourcePriority priority_;
144:   const bool auto_configured_for_http3_{};
145: };
